solutions.javascript:
// Define a middleware function to handle GET requests
// The middleware function should resolve the route based on the query parameter
// The route resolution should be case-insensitive
function middleware(req, res, next) {
  const param = req.query.param;
  const route = param.toLowerCase();
  res.writeHead(200, { 'Content-Type': 'text/plain' });
  res.end(route);
}

// Export the middleware function
module.exports = middleware;
